frappe.ui.form.on('Quotation', {
    party_name: function(frm) {
        if (frm.doc.quotation_to && frm.doc.party_name) {
            frappe.db.get_value(frm.doc.quotation_to, frm.doc.party_name, 'custom_interne_kundennummer')
                .then(r => {
                    if (r && r.message) {
                        frm.set_value('custom_interne_kundennummer', r.message.custom_interne_kundennummer);
                    }
                });
        } else {
            frm.set_value('custom_interne_kundennummer', '(unbekannt)');
        }
    }
});

frappe.ui.form.on('Opportunity', {
    refresh: function(frm) {
        frm.add_custom_button(__('Copy Customer Name'), function() {
            if (frm.doc.customer_name) {
                // Text in die Zwischenablage kopieren
                navigator.clipboard.writeText(frm.doc.customer_name)
                    .then(() => {
                        frappe.show_alert({
                            message: __('Customer Name copied to clipboard: {0}', [frm.doc.customer_name]),
                            indicator: 'green'
                        });
                    })
                    .catch(err => {
                        frappe.msgprint({
                            title: __('Error'),
                            message: __('Failed to copy Customer Name to clipboard.'),
                            indicator: 'red'
                        });
                        console.error('Clipboard write failed', err);
                    });
            } else {
                frappe.msgprint(__('No Customer Name to copy.'));
            }
        }, __("Aktionen")); // Optional: Button-Gruppe, in der der Button angezeigt wird
    }
});

frappe.ui.form.on('Opportunity', {
    onload: function(frm) {
        // kurze Verzögerung, damit ERPNext seine Standardlogik zuerst ausführt
        setTimeout(() => {
            if (frm.doc.phone && frm.doc.contact_mobile) {
                if (frm.doc.phone === frm.doc.contact_mobile) {
                    frm.set_value('contact_mobile', '');
                }
            }
        }, 200);
    }
});

frappe.ui.form.on('Ersteingabe Lead AZ-IT', {
    validate: function(frm) {
        // Funktion zur Bereinigung und Validierung der Telefonnummer
        function validatePhoneNumber(phoneNumber, fieldName) {
            if (phoneNumber) {
                // Überprüfen, ob die Telefonnummer mit einem + beginnt
                if (phoneNumber.charAt(0) !== '+') {
                    frappe.throw("Die Telefonnummer in " + fieldName + " muss mit einem + und einer Länderkennung beginnen. Beispiel: +49123456");
                }

                // Entfernen aller nicht erlaubten Zeichen aus der Eingabe
                phoneNumber = phoneNumber.replace(/\s+/g, '');   // Leerzeichen entfernen
                phoneNumber = phoneNumber.replace(/\-+/g, '');   // Bindestriche entfernen
                phoneNumber = phoneNumber.replace(/\(+/g, '');   // Öffnende Klammern entfernen
                phoneNumber = phoneNumber.replace(/\)+/g, '');   // Schließende Klammern entfernen
                phoneNumber = phoneNumber.replace(/\[+/g, '');   // Eckige Klammern entfernen
                phoneNumber = phoneNumber.replace(/\]+/g, '');   // Schließende eckige Klammern entfernen
                phoneNumber = phoneNumber.replace(/\/+/g, '');   // Schrägstriche entfernen

                // Bereinigte Telefonnummer zurücksetzen
                frm.set_value(fieldName, phoneNumber);
            }
        }

        // Beide Telefonnummernfelder überprüfen und berichtigen
        validatePhoneNumber(frm.doc.telefon, 'telefon');
        validatePhoneNumber(frm.doc.telefon_zentrale, 'telefon_zentrale');
    }
});

frappe.ui.form.on('Customer', {
    onload: function(frm) {
        // Only proceed if the internal customer number field is empty
        if (!frm.doc.custom_interne_kundennummer) {
            generate_customer_number(frm);
        }
    },

    refresh: function(frm) {
        // Also check on refresh to handle existing documents
        if (!frm.doc.custom_interne_kundennummer) {
            generate_customer_number(frm);
        }
    }
});

function generate_customer_number(frm) {
    // Make a server call to get the next customer number
    frappe.call({
        method: 'frappe.client.get_list',
        args: {
            doctype: 'Customer',
            fields: ['custom_interne_kundennummer'],
            filters: [
                ['custom_interne_kundennummer', '!=', ''],
                ['custom_interne_kundennummer', '>=', '20000']  // Only consider numbers >= 20000
            ],
            order_by: 'custom_interne_kundennummer desc',
            limit_page_length: 1
        },
        callback: function(r) {
            let next_number = 20000; // Starting number

            if (r.message && r.message.length > 0) {
                let highest_number = r.message[0].custom_interne_kundennummer;

                // Convert to integer and add 1
                let current_number = parseInt(highest_number);

                if (!isNaN(current_number) && current_number >= 20000) {
                    next_number = current_number + 1;
                }
            }

            // Set the value in the field (exactly 5 characters)
            frm.set_value('custom_interne_kundennummer', String(next_number).padStart(5, '0'));
        }
    });
}

