frappe.ui.form.on('Lead', {
    custom_aktueller_primärkontakt: function(frm) {
        if (frm.doc.custom_aktueller_primärkontakt) {
            frappe.db.get_doc('Contact', frm.doc.custom_aktueller_primärkontakt)
                .then(contact => {
                    // Übernahme der Salutation
                    if (contact.salutation) {
                        frm.set_value('salutation', contact.salutation);
                    }
                    // Übernahme von first_name, middle_name, last_name
                    if (contact.first_name) {
                        frm.set_value('first_name', contact.first_name);
                    }
                    if (contact.middle_name) {
                        frm.set_value('middle_name', contact.middle_name);
                    }
                    if (contact.last_name) {
                        frm.set_value('last_name', contact.last_name);
                    }
                });
        }
    },
    
    // Bei Änderungen in Lead soll das Skript ausgelöst werden
    refresh: function(frm) {
        frm.trigger('custom_aktueller_primärkontakt');
    }
});

