frappe.ui.form.on('Lead', {
    onload_post_render: function (frm) {
        frm.__original_custom_angebot_zugesendet = frm.doc.custom_angebot_zugesendet;
    },
    before_save: function (frm) {
        if (
            frm.__original_custom_angebot_zugesendet === 0 &&
            frm.doc.custom_angebot_zugesendet === 1
        ) {
            frappe.call({
                method: 'frappe.client.insert',
                args: {
                    doc: {
                        doctype: 'ToDo',
                        date: frappe.datetime.add_days(frappe.datetime.get_today(), 10),
                        allocated_to: 'k.reichegger@az-it.systems',
                        description: `WVL ${frm.doc.company_name} nach Angebot<br><br>Vor 10 Tagen wurde ein Angebot versendet.<br>Bitte nachhaken.<br>Das Angebot befindet sich links als Dateianhang im verknüpften Datensatz.`,
                        reference_type: 'Lead',
                        reference_name: frm.doc.name,
                        status: 'Open',
                        priority: 'Medium',
                        color: '#e74c3c',
                    }
                },
                callback: function (r) {
                    if (r.exc) {
                        frappe.msgprint(__('Das ToDo konnte nicht erstellt werden.'));
                    } else {
                        frappe.msgprint(__('Ein ToDo wurde erfolgreich erstellt.'));
                    }
                }
            });
        }
    },
    after_save: function (frm) {
        frm.__original_custom_angebot_zugesendet = frm.doc.custom_angebot_zugesendet;
    },
});

