frappe.ui.form.on('ToDo', {
    onload: function(frm) {
        if (frm.doc.reference_name && frm.doc.reference_type) {
            frappe.call({
                method: "frappe.client.get",
                args: {
                    doctype: frm.doc.reference_type,
                    name: frm.doc.reference_name
                },
                callback: function(response) {
                    if (response.message) {
                        let linked_doc = response.message;

                        if (linked_doc.notes && linked_doc.notes.length > 0) {
                            // Sortiere die Notizen basierend auf dem 'added_on'-Zeitpunkt in absteigender Reihenfolge
                            linked_doc.notes.sort((a, b) => new Date(b.added_on) - new Date(a.added_on));

                            // Nimm die erste Notiz aus der sortierten Liste, die jetzt die neueste ist
                            let latest_note = linked_doc.notes[0];

                            if (latest_note) {
                                frm.set_value('custom_letzter_kommentar_an_verknüpften_daten', latest_note.note);
                                frm.save();
                            }
                        }
                    }
                }
            });
        }
    }
});
